#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int count_inversions(int *arr, int n) {
    int inversions = 0;
    for (int i = 0; i < n; i++) {
        for (int j = i + 1; j < n; j++) {
            if (arr[i] > arr[j]) {
                inversions++;
            }
        }
    }
    return inversions;
}

void generate_permutations(int *arr, int n, int **permutations, int *count) {
    if (n == 1) {
        permutations[*count] = (int*)malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) {
            permutations[*count][i] = arr[i];
        }
        (*count)++;
    } else {
        for (int i = 0; i < n; i++) {
            int temp = arr[i];
            for (int j = i + 1; j < n; j++) {
                arr[i] = arr[j];
                arr[j] = temp;
            }
            generate_permutations(arr, n - 1, permutations, count);
            for (int j = i + 1; j < n; j++) {
                arr[j] = arr[i];
                arr[i] = temp;
            }
        }
    }
}

int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int N;
        scanf("%d", &N);
        int **matrix = (int**)malloc(N * sizeof(int*));
        for (int i = 0; i < N; i++) {
            matrix[i] = (int*)malloc(2 * sizeof(int));
            scanf("%d %d", &matrix[i][0], &matrix[i][1]);
        }
        int *arr = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            arr[i] = i;
        }
        int **permutations = (int**)malloc(1000000 * sizeof(int*));
        int count = 0;
        generate_permutations(arr, N, permutations, &count);
        int alex_wins = 0;
        int fedya_wins = 0;
        for (int i = 0; i < count; i++) {
            int inversions = count_inversions(permutations[i], N);
            int valid = 1;
            for (int j = 0; j < N; j++) {
                if (permutations[i][j] < matrix[j][0] || permutations[i][j] > matrix[j][1]) {
                    valid = 0;
                    break;
                }
            }
            if (valid) {
                if (inversions % 2 == 0) {
                    alex_wins = 1;
                } else {
                    fedya_wins = 1;
                }
            }
        }
