import java.util.Scanner;
public class Main {
    public static int count_inversions(int[] arr) {
        int inversions = 0;
        for (int i = 0; i < arr.length; i++) {
            for (int j = i + 1; j < arr.length; j++) {
                if (arr[i] > arr[j]) {
                    inversions++;
                }
            }
        }
        return inversions;
    }

    public static void generate_permutations(int[] arr, int n, int[][] permutations, int[] count) {
        if (n == 1) {
            permutations[count[0]] = arr.clone();
            count[0]++;
        } else {
            for (int i = 0; i < n; i++) {
                int temp = arr[i];
                for (int j = i + 1; j < n; j++) {
                    arr[i] = arr[j];
                    arr[j] = temp;
                }
                generate_permutations(arr, n - 1, permutations, count);
                for (int j = i + 1; j < n; j++) {
                    arr[j] = arr[i];
                    arr[i] = temp;
                }
            }
        }
    }

